using System;
using System.Collections.Generic;
using System.Linq;
using SensCalibr8.Data.Persistence;

namespace SensCalibr8.Data.Repositories
{
    public sealed class HtmlReportInputRepository
    {
        private readonly RepositoryExecution execution;
        public HtmlReportInputRepository(SqliteConnectionFactory factory,IDataFailureReporter reporter=null){execution=new RepositoryExecution(factory,reporter);}
        public HtmlReportInput Read(long profileId)
        {
            if(profileId<=0)throw new ArgumentOutOfRangeException(nameof(profileId));
            return execution.Read("read html report input",c=>{AnalysisProfileIdentity profile=Profile(c,profileId);Finalized(c,profileId);return new HtmlReportInput(profile,Scores(c,profileId),Shots(c,profileId),Tracking(c,profileId),Winners(c,profileId),Reactions(c,profileId),ProfileComparisons(c),Outliers(c,profileId),Fatigue(c,profileId),Warnings(c,profileId),Significance(c,profileId));});
        }
        private static AnalysisProfileIdentity Profile(SqliteDatabaseConnection c,long id){var r=c.Query("SELECT id,name,mouse_dpi FROM profiles WHERE id=@id;",new Dictionary<string,object>{{"@id",id}});if(r.Count!=1)throw new InvalidOperationException("HTML report profile was not found.");return new AnalysisProfileIdentity(Convert.ToInt64(r[0]["id"]),Convert.ToString(r[0]["name"]),Convert.ToInt64(r[0]["mouse_dpi"]));}
        private static void Finalized(SqliteDatabaseConnection c,long id){long shots=Convert.ToInt64(c.Scalar("SELECT COUNT(*) FROM shots WHERE profile_id=@id AND is_adaptation_shot IS NULL;",new Dictionary<string,object>{{"@id",id}})),tracking=Convert.ToInt64(c.Scalar("SELECT COUNT(*) FROM tracking_data WHERE profile_id=@id AND is_adaptation_trial IS NULL;",new Dictionary<string,object>{{"@id",id}}));if(shots!=0||tracking!=0)throw new InvalidOperationException("HTML report rejects unfinalized adaptation evidence.");}
        private static IReadOnlyList<HtmlReportScoreRecord> Scores(SqliteDatabaseConnection c,long id)=>c.Query(@"SELECT st.cycle_id,st.phase,st.edpi,b.sensitivity_value,st.avg_performance_score,st.grade,st.formula_version,cfg.config_version,b.completed_date FROM sensitivity_tests st JOIN protocol_batteries b ON b.id=st.battery_id JOIN calibration_configs cfg ON cfg.id=st.calibration_config_id WHERE st.profile_id=@id AND b.profile_id=@id AND b.completed_date IS NOT NULL AND (SELECT COUNT(*) FROM sessions x WHERE x.battery_id=b.id)=4 AND (SELECT COUNT(DISTINCT x.mode) FROM sessions x WHERE x.battery_id=b.id)=4 ORDER BY st.id;",new Dictionary<string,object>{{"@id",id}}).Select(r=>new HtmlReportScoreRecord(Convert.ToInt64(r["cycle_id"]),Convert.ToInt64(r["phase"]),Convert.ToDouble(r["edpi"]),Convert.ToDouble(r["sensitivity_value"]),Convert.ToDouble(r["avg_performance_score"]),r["grade"]==null?null:Convert.ToString(r["grade"]),Convert.ToString(r["formula_version"]),Convert.ToString(r["config_version"]),Convert.ToString(r["completed_date"]))).ToArray();
        private static IReadOnlyList<HtmlReportShotRecord> Shots(SqliteDatabaseConnection c,long id)=>c.Query(@"SELECT s.id AS session_id,s.date,b.cycle_id,b.phase,s.mode,b.sensitivity_value,p.mouse_dpi*b.sensitivity_value AS edpi,sh.final_precision_error,sh.signed_overflick_underflick_deg,sh.submovement_count,sh.spawn_position,cfg.config_version FROM shots sh JOIN profiles p ON p.id=sh.profile_id JOIN sessions s ON s.id=sh.session_id JOIN protocol_batteries b ON b.id=s.battery_id JOIN calibration_configs cfg ON cfg.id=s.calibration_config_id WHERE sh.profile_id=@id AND s.profile_id=@id AND sh.is_adaptation_shot=0 ORDER BY sh.id;",new Dictionary<string,object>{{"@id",id}}).Select(r=>new HtmlReportShotRecord(Convert.ToInt64(r["session_id"]),Convert.ToString(r["date"]),Convert.ToInt64(r["cycle_id"]),Convert.ToInt64(r["phase"]),Convert.ToString(r["mode"]),Convert.ToDouble(r["sensitivity_value"]),Convert.ToDouble(r["edpi"]),Convert.ToDouble(r["final_precision_error"]),r["signed_overflick_underflick_deg"]==null?(double?)null:Convert.ToDouble(r["signed_overflick_underflick_deg"]),r["submovement_count"]==null?(long?)null:Convert.ToInt64(r["submovement_count"]),Convert.ToString(r["spawn_position"]),Convert.ToString(r["config_version"]))).ToArray();
        private static IReadOnlyList<HtmlReportTrackingErrorRecord> Tracking(SqliteDatabaseConnection c,long id)=>c.Query(@"SELECT s.date,b.cycle_id,b.phase,b.sensitivity_value,w.tracking_deviation_rms_deg,cfg.config_version FROM tracking_windows w JOIN tracking_data t ON t.id=w.tracking_trial_id JOIN sessions s ON s.id=t.session_id JOIN protocol_batteries b ON b.id=s.battery_id JOIN calibration_configs cfg ON cfg.id=s.calibration_config_id WHERE t.profile_id=@id AND s.profile_id=@id AND t.is_adaptation_trial=0 ORDER BY w.id;",new Dictionary<string,object>{{"@id",id}}).Select(r=>new HtmlReportTrackingErrorRecord(Convert.ToString(r["date"]),Convert.ToInt64(r["cycle_id"]),Convert.ToInt64(r["phase"]),Convert.ToDouble(r["sensitivity_value"]),Convert.ToDouble(r["tracking_deviation_rms_deg"]),Convert.ToString(r["config_version"]))).ToArray();
        private static IReadOnlyList<HtmlReportWinnerRecord> Winners(SqliteDatabaseConnection c,long id)=>c.Query(@"SELECT cy.cycle_number,h.phase_number,h.winner_edpi,pc.sensitivity_value,h.timestamp FROM phase_history h JOIN cycles cy ON cy.id=h.cycle_id JOIN protocol_candidates pc ON pc.profile_id=h.profile_id AND pc.cycle_id=h.cycle_id AND pc.phase=h.phase_number AND pc.edpi=h.winner_edpi WHERE h.profile_id=@id ORDER BY cy.cycle_number,h.phase_number;",new Dictionary<string,object>{{"@id",id}}).Select(r=>new HtmlReportWinnerRecord(Convert.ToInt64(r["cycle_number"]),Convert.ToInt64(r["phase_number"]),Convert.ToDouble(r["winner_edpi"]),Convert.ToDouble(r["sensitivity_value"]),Convert.ToString(r["timestamp"]))).ToArray();
        private static IReadOnlyList<HtmlReportReactionRecord> Reactions(SqliteDatabaseConnection c,long id)=>c.Query(@"SELECT s.id AS session_id,s.date,b.cycle_id,b.phase,s.mode,b.sensitivity_value,CASE s.mode WHEN 'flick_close' THEN (sh.resolution_timestamp-sh.spawn_timestamp)*1000.0 WHEN 'flick_far' THEN CASE WHEN sh.first_mouse_movement_timestamp IS NULL THEN NULL ELSE (sh.resolution_timestamp-sh.first_mouse_movement_timestamp)*1000.0 END WHEN 'micro_correction' THEN (sh.resolution_timestamp-sh.spawn_timestamp)*1000.0 ELSE NULL END AS reaction_time_ms,cfg.config_version FROM shots sh JOIN sessions s ON s.id=sh.session_id JOIN protocol_batteries b ON b.id=s.battery_id JOIN calibration_configs cfg ON cfg.id=s.calibration_config_id WHERE sh.profile_id=@id AND s.profile_id=@id AND sh.is_adaptation_shot=0 AND s.mode IN ('flick_close','flick_far','micro_correction') ORDER BY sh.id;",new Dictionary<string,object>{{"@id",id}}).Where(r=>r["reaction_time_ms"]!=null).Select(r=>new HtmlReportReactionRecord(Convert.ToInt64(r["session_id"]),Convert.ToString(r["date"]),Convert.ToInt64(r["cycle_id"]),Convert.ToInt64(r["phase"]),Convert.ToString(r["mode"]),Convert.ToDouble(r["sensitivity_value"]),Convert.ToDouble(r["reaction_time_ms"]),Convert.ToString(r["config_version"]))).ToArray();
        private static IReadOnlyList<HtmlReportProfileComparisonRecord> ProfileComparisons(SqliteDatabaseConnection c)=>c.Query(@"SELECT p.id,p.name,cy.cycle_number,h.winner_edpi FROM profiles p JOIN phase_history h ON h.profile_id=p.id AND h.phase_number=3 JOIN cycles cy ON cy.id=h.cycle_id ORDER BY p.id,cy.cycle_number;",null).Select(r=>new HtmlReportProfileComparisonRecord(Convert.ToInt64(r["id"]),Convert.ToString(r["name"]),Convert.ToInt64(r["cycle_number"]),Convert.ToDouble(r["winner_edpi"]))).ToArray();
        private static IReadOnlyList<HtmlReportOutlierRecord> Outliers(SqliteDatabaseConnection c,long id)=>c.Query(@"SELECT r.phase,r.mode,r.sensitivity_value,r.metric_name,r.inclusive_mean,r.flagged_excluded_mean,r.observation_count,r.flagged_count,r.algorithm_version,cfg.config_version FROM outlier_analysis_runs r JOIN calibration_configs cfg ON cfg.id=r.calibration_config_id WHERE r.profile_id=@id ORDER BY r.id;",new Dictionary<string,object>{{"@id",id}}).Select(r=>new HtmlReportOutlierRecord(Convert.ToInt64(r["phase"]),Convert.ToString(r["mode"]),Convert.ToDouble(r["sensitivity_value"]),Convert.ToString(r["metric_name"]),Convert.ToDouble(r["inclusive_mean"]),Convert.ToDouble(r["flagged_excluded_mean"]),Convert.ToInt64(r["observation_count"]),Convert.ToInt64(r["flagged_count"]),Convert.ToString(r["algorithm_version"]),Convert.ToString(r["config_version"]))).ToArray();
        private static IReadOnlyList<HtmlReportFatigueRecord> Fatigue(SqliteDatabaseConnection c,long id)=>c.Query(@"SELECT id,date,mode,fatigue_flag,fatigue_score_change_percentage,fatigue_algorithm_version FROM sessions WHERE profile_id=@id ORDER BY id;",new Dictionary<string,object>{{"@id",id}}).Select(r=>new HtmlReportFatigueRecord(Convert.ToInt64(r["id"]),Convert.ToString(r["date"]),Convert.ToString(r["mode"]),Convert.ToInt64(r["fatigue_flag"])==1,r["fatigue_score_change_percentage"]==null?(double?)null:Convert.ToDouble(r["fatigue_score_change_percentage"]),r["fatigue_algorithm_version"]==null?null:Convert.ToString(r["fatigue_algorithm_version"]))).ToArray();
        private static IReadOnlyList<HtmlReportWarningRecord> Warnings(SqliteDatabaseConnection c,long id)=>c.Query(@"SELECT flag_type,triggered_date,edpi_at_trigger,acknowledged FROM injury_risk_flags WHERE profile_id=@id ORDER BY id;",new Dictionary<string,object>{{"@id",id}}).Select(r=>new HtmlReportWarningRecord(Convert.ToString(r["flag_type"]),Convert.ToString(r["triggered_date"]),Convert.ToDouble(r["edpi_at_trigger"]),Convert.ToInt64(r["acknowledged"])==1)).ToArray();
        private static IReadOnlyList<HtmlReportSignificanceRecord> Significance(SqliteDatabaseConnection c,long id)=>c.Query(@"SELECT phase,candidate_a_edpi,candidate_b_edpi,alpha,p_value,is_significant,result,test_method,formula_version FROM significance_tests WHERE profile_id=@id ORDER BY id;",new Dictionary<string,object>{{"@id",id}}).Select(r=>new HtmlReportSignificanceRecord(Convert.ToInt64(r["phase"]),Convert.ToDouble(r["candidate_a_edpi"]),Convert.ToDouble(r["candidate_b_edpi"]),Convert.ToDouble(r["alpha"]),Convert.ToDouble(r["p_value"]),Convert.ToInt64(r["is_significant"])==1,Convert.ToString(r["result"]),Convert.ToString(r["test_method"]),Convert.ToString(r["formula_version"]))).ToArray();
    }
}
